import React, { useEffect, useState } from 'react';

export default function AppointmentsTab() {
  const [appointments, setAppointments] = useState([]);
  const [doctorName, setDoctorName] = useState('');
  const [date, setDate] = useState('');
  const [reason, setReason] = useState('');

  const token = localStorage.getItem('token');

  useEffect(() => {
    fetchAppointments();
  }, []);

  async function fetchAppointments() {
    const res = await fetch('http://localhost:5000/api/appointments', { headers: { Authorization: `Bearer ${token}` } });
    const data = await res.json();
    setAppointments(data);
  }

  async function add(e) {
    e.preventDefault();
    await fetch('http://localhost:5000/api/appointments', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
      body: JSON.stringify({ doctorName, date, reason })
    });
    setDoctorName(''); setDate(''); setReason('');
    fetchAppointments();
  }

  return (
    <div>
      <h3>Schedule Appointment</h3>
      <form onSubmit={add} style={{ maxWidth: 540 }}>
        <div className="form-row">
          <label>Doctor Name</label>
          <input value={doctorName} onChange={e => setDoctorName(e.target.value)} />
        </div>
        <div className="form-row">
          <label>Date & time</label>
          <input type="datetime-local" value={date} onChange={e => setDate(e.target.value)} />
        </div>
        <div className="form-row">
          <label>Reason</label>
          <input value={reason} onChange={e => setReason(e.target.value)} />
        </div>
        <div><button type="submit">Schedule</button></div>
      </form>

      <h3 style={{ marginTop: 16 }}>Your Appointments</h3>
      {appointments.map(a => (
        <div key={a._id} className="list-item">
          <strong>{a.doctorName}</strong> — {new Date(a.date).toLocaleString()}<br />
          {a.reason}
        </div>
      ))}
    </div>
  );
}
